ALGORITHM HalfAdderDesign
INPUT: Two 1-bit inputs A, B
OUTPUT: Sum (S) and Carry (C_out)

BEGIN
 // Step 1: Problem Statement
 // Design a circuit that adds two binary bits
 // Inputs: A, B (each can be 0 or 1)
 // Outputs: Sum and Carry

 // Step 2: Determine Inputs and Outputs
 INPUTS: A, B // Two 1-bit binary numbers
 OUTPUTS: S, C_out // Sum and Carry bits

 // Step 3: Truth Table Construction
 // All possible input combinations: 2^2 = 4
 // A B | C_out S
 // 0 0 | 0 0
 // 0 1 | 0 1
 // 1 0 | 0 1
 // 1 1 | 1 0

 // Step 4: Boolean Function Derivation
 // From truth table analysis:
 // C_out = A AND B (Only 1 when both inputs are 1)
 // S = A XOR B (1 when inputs are different)

 // Equivalent expressions using fundamental gates:
 // S = (A OR B) AND (NOT (A AND B))
 // C_out = A AND B

 // Step 5: Implementation using logic gates
 FUNCTION ComputeSum(A, B):
 temp1 = NOT(A AND B) // NAND gate
 temp2 = A OR B // OR gate
 S = temp2 AND temp1 // AND gate (XOR implementation)
 RETURN S

 FUNCTION ComputeCarry(A, B):
 C_out = A AND B // AND gate
 RETURN C_out

 // Main computation
 S = ComputeSum(A, B)
 C_out = ComputeCarry(A, B)

 OUTPUT: S, C_out
END

/*
 * Combinational Logic: Half Adder and Multiplexer
 * Demonstrates fundamental combinational circuits in C
 * university 2022 Scheme - CSE Digital Electronics
 */

#include <stdio.h>
#include <stdlib.h>

// Define Boolean constants
#define FALSE 0
#define TRUE 1
typedef int bit;

// ============== BASIC LOGIC GATES ==============

bit NOT(bit a) {
 return !a;
}

bit AND(bit a, bit b) {
 return a & b;
}

bit OR(bit a, bit b) {
 return a | b;
}

bit NAND(bit a, bit b) {
 return NOT(AND(a, b));
}

// XOR using basic gates: (A OR B) AND NOT(A AND B)
bit XOR(bit a, bit b) {
 bit a_and_b = AND(a, b);
 bit not_a_and_b = NOT(a_and_b);
 bit a_or_b = OR(a, b);
 return AND(a_or_b, not_a_and_b);
}

// ============== HALF ADDER ==============

/*
 * Half Adder Circuit
 * Inputs: Two 1-bit numbers a, b
 * Outputs: sum (S) and carry (C_out)
 * Logic:
 * S = A XOR B
 * C_out = A AND B
 */
void half_adder(bit a, bit b, bit *sum, bit *carry) {
 *sum = XOR(a, b); // Sum is XOR of inputs
 *carry = AND(a, b); // Carry is AND of inputs
}

// ============== 2-TO-1 MULTIPLEXER ==============

/*
 * 2-to-1 Multiplexer
 * 
 * A multiplexer selects one of multiple inputs based on select lines
 * For 2-to-1 MUX: 2 data inputs (I0, I1), 1 select line (S), 1 output (Y)
 * 
 * Truth Table:
 * S | I1 | I0 | Y
 * --+----+----+--
 * 0 | X | 0 | 0
 * 0 | X | 1 | 1
 * 1 | 0 | X | 0
 * 1 | 1 | X | 1
 * 
 * Boolean Function: Y = (S' AND I0) OR (S AND I1)
 */
bit mux_2to1(bit I0, bit I1, bit S) {
 bit S_not = NOT(S); // NOT gate for select
 bit term1 = AND(S_not, I0); // AND: S' * I0
 bit term2 = AND(S, I1); // AND: S * I1
 bit Y = OR(term1, term2); // OR: (S'*I0) + (S*I1)
 return Y;
}

// ============== 4-TO-1 MULTIPLEXER (using 2-to-1 MUX) ==============

/*
 * 4-to-1 Multiplexer using 2-to-1 MUX
 * Inputs: 4 data lines (I0, I1, I2, I3), 2 select lines (S0, S1)
 * Output: 1 output line (Y)
 * 
 * Selection:
 * S1 S0 | Output
 * ------+--------
 * 0 0 | I0
 * 0 1 | I1
 * 1 0 | I2
 * 1 1 | I3
 */
bit mux_4to1(bit I0, bit I1, bit I2, bit I3, bit S0, bit S1) {
 // First stage: Two 2-to-1 MUXes
 bit mux_out_0 = mux_2to1(I0, I1, S0); // Selects between I0, I1
 bit mux_out_1 = mux_2to1(I2, I3, S0); // Selects between I2, I3

 // Second stage: 1 MUX to select final output
 bit Y = mux_2to1(mux_out_0, mux_out_1, S1);
 return Y;
}

// ============== TEST FUNCTIONS ==============

void test_half_adder() {
 bit a, b, sum, carry;

 printf("========================================\n");
 printf(" HALF ADDER TRUTH TABLE \n");
 printf("========================================\n");
 printf(" A B | Sum Carry\n");
 printf("---------|------------\n");

 for (a = 0; a <= 1; a++) {
 for (b = 0; b <= 1; b++) {
 half_adder(a, b, &sum, &carry);
 printf(" %d %d | %d %d\n", a, b, sum, carry);
 }
 }
}

void test_mux_2to1() {
 bit I0, I1, S, Y;

 printf("\n========================================\n");
 printf(" 2-TO-1 MULTIPLEXER TRUTH TABLE \n");
 printf("========================================\n");
 printf(" S I1 I0 | Y\n");
 printf("------------|------\n");

 for (S = 0; S <= 1; S++) {
 for (I1 = 0; I1 <= 1; I1++) {
 for (I0 = 0; I0 <= 1; I0++) {
 Y = mux_2to1(I0, I1, S);
 printf(" %d %d %d | %d\n", S, I1, I0, Y);
 }
 }
 }
}

void test_mux_4to1() {
 printf("\n========================================\n");
 printf(" 4-TO-1 MULTIPLEXER DEMONSTRATION \n");
 printf("========================================\n");

 // Test case: I0=0, I1=1, I2=0, I3=1, varying select lines
 bit I0 = 0, I1 = 1, I2 = 0, I3 = 1;

 printf("Inputs: I0=%d, I1=%d, I2=%d, I3=%d\n\n", I0, I1, I2, I3);

 printf("S1 S0 | Output (Y)\n");
 printf("------|------------\n");

 int s1, s0;
 for (s1 = 0; s1 <= 1; s1++) {
 for (s0 = 0; s0 <= 1; s0++) {
 bit Y = mux_4to1(I0, I1, I2, I3, s0, s1);
 printf(" %d %d | %d\n", s1, s0, Y);
 }
 }
}

// ============== MAIN ==============

int main() {
 printf("COMBINATIONAL LOGIC CIRCUITS\n");
 printf("=============================\n\n");

 // Test Half Adder
 test_half_adder();

 // Test 2-to-1 Multiplexer
 test_mux_2to1();

 // Test 4-to-1 Multiplexer (hierarchical design)
 test_mux_4to1();

 return 0;
}
